targets.expr:
min by (job) (
  live_overlay_bridge_scrape_success{
    job=~"$job",
    bridge=~"uptimerobot|github_workflow"
  }
  and on(job, bridge) (
    live_overlay_bridge_enabled{
      job=~"$job",
      bridge=~"uptimerobot|github_workflow"
    } == 1
  )
)
or on(job) label_replace(vector(-1), "job", "live_overlay", "", "")

(
  live_overlay_last_bar_age_seconds{job=~"$job"}
  and on(job, instance) (live_overlay_last_bar_age_known{job=~"$job"} == 1)
) or on(job, instance) (
  live_overlay_last_bar_age_known{job=~"$job"} * 0 - 1
)

(
  absent(live_overlay_uptime_seconds{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_overlay_fresh{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_market_us_open{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_last_bar_age_known{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_smc_live_requests_total{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_smc_live_success_total{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_smc_live_errors_total{job=~"$job"}) or vector(0)
) + (
  absent(live_overlay_smc_live_latency_ms_count{job=~"$job"}) or vector(0)
)

(
  histogram_quantile(0.95, sum by (le) (
    rate(live_overlay_smc_live_latency_ms_bucket{job=~"$job"}[5m])
  ))
  and on() (sum(rate(live_overlay_smc_live_latency_ms_count{job=~"$job"}[5m])) > 0)
) or vector(0)

(
  histogram_quantile(0.99, sum by (le) (
    rate(live_overlay_smc_live_latency_ms_bucket{job=~"$job"}[5m])
  ))
  and on() (sum(rate(live_overlay_smc_live_latency_ms_count{job=~"$job"}[5m])) > 0)
) or vector(0)

(
  live_overlay_overlay_age_seconds{job=~"$job"}
  and on(job, instance) (live_overlay_overlay_age_known{job=~"$job"} == 1)
) or on(job, instance) (
  live_overlay_overlay_age_known{job=~"$job"} * 0 - 1
)

(
  live_overlay_last_bar_age_seconds{job=~"$job"}
  and on(job, instance) (live_overlay_last_bar_age_known{job=~"$job"} == 1)
) or on(job, instance) (
  live_overlay_last_bar_age_known{job=~"$job"} * 0 - 1
)

100 * (
  (
    live_overlay_overlay_age_seconds{job=~"$job"}
    and on(job, instance) (live_overlay_overlay_age_known{job=~"$job"} == 1)
  ) or on(job, instance) (
    live_overlay_overlay_age_known{job=~"$job"} * 0 - 1
  )
) / clamp_min(live_overlay_max_stale_seconds{job=~"$job"}, 1)

max by (job, bridge, error) (
  live_overlay_bridge_error_info{
    job=~"$job",
    bridge="railway_metrics",
    error!="none"
  }
) or vector(0)
